import SwiftUI
import AppKit
import AIUsagesTrackersLib

struct SegmentCardView: View {
    let preferences: any AppPreferences
    @Bindable var store: UsageStore
    let isDark: Bool
    let index: Int
    let canMoveUp: Bool
    let canMoveDown: Bool
    let onMoveUp: () -> Void
    let onMoveDown: () -> Void
    let onRequestDelete: () -> Void

    @State private var isExpanded: Bool = false

    private var segment: MenuBarSegmentConfig? {
        guard preferences.menuBarSegments.indices.contains(index) else { return nil }
        return preferences.menuBarSegments[index]
    }

    var body: some View {
        if let segment {
            DisclosureGroup(isExpanded: $isExpanded) {
                SegmentEditor(
                    preferences: preferences,
                    store: store,
                    index: index
                )
                .padding(.top, 8)
            } label: {
                header(for: segment)
            }
            .padding(.vertical, 4)
        }
    }

    private func header(for segment: MenuBarSegmentConfig) -> some View {
        HStack(spacing: 8) {
            summary(for: segment)
                .frame(maxWidth: .infinity, alignment: .leading)

            HStack(spacing: 4) {
