1	import Foundation
2	import Observation
3	
4	// MARK: - Protocol
5	
6	/// Single source of truth for user-adjustable runtime behaviour.
7	/// Injectable so tests can swap in `InMemoryAppPreferences`.
8	@MainActor
9	public protocol AppPreferences: AnyObject, Observable, Sendable {
10	    var refreshInterval: RefreshInterval { get set }
11	    var launchAtLogin: Bool { get set }
12	    var logLevel: LogLevel { get set }
13	    var menuBarSegments: [MenuBarSegmentConfig] { get set }
14	    /// Tracks whether seeding has already run — distinguishes "fresh install"
15	    /// from "user deleted all segments." False on a brand-new UserDefaults suite.
16	    var menuBarSegmentsInitialized: Bool { get set }
17	}
18	
19	// MARK: - UserDefaults-backed implementation
20	
21	@Observable
22	@MainActor
23	public final class UserDefaultsAppPreferences: AppPreferences {
24	    private let defaults: UserDefaults
25	
26	    public init(defaults: UserDefaults = .standard) {
27	        self.defaults = defaults
28	    }
29	
30	    public var refreshInterval: RefreshInterval {
31	        get {
32	            let raw = defaults.integer(forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
33	            if raw == 0 { return .default }
34	            return RefreshInterval(clamping: raw)
35	        }
36	        set {
37	            defaults.set(newValue.seconds, forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
38	        }
39	    }
40	
41	    public var launchAtLogin: Bool {
42	        get { defaults.bool(forKey: AppPreferenceKeys.launchAtLogin.rawValue) }
43	        set { defaults.set(newValue, forKey: AppPreferenceKeys.launchAtLogin.rawValue) }
44	    }
45	
46	    public var logLevel: LogLevel {
47	        get {
48	            let raw = defaults.string(forKey: AppPreferenceKeys.logLevel.rawValue) ?? ""
49	            if raw.isEmpty { return .info }
50	            return LogLevel.from(string: raw)
51	        }
52	        set {
53	            defaults.set(newValue.label.lowercased(), forKey: AppPreferenceKeys.logLevel.rawValue)
54	        }
55	    }
56	
57	    public var menuBarSegments: [MenuBarSegmentConfig] {
58	        get {
59	            guard let data = defaults.data(forKey: AppPreferenceKeys.menuBarSegments.rawValue) else {
60	                return []
61	            }
62	            do {
63	                return try JSONDecoder().decode([MenuBarSegmentConfig].self, from: data)
64	            } catch {
65	                Loggers.app.log(.error, "Failed to decode menuBarSegments from UserDefaults: \(error)")
66	                return []
67	            }
68	        }
69	        set {
70	            do {
71	                let data = try JSONEncoder().encode(newValue)
72	                defaults.set(data, forKey: AppPreferenceKeys.menuBarSegments.rawValue)
73	            } catch {
74	                Loggers.app.log(.error, "Failed to encode menuBarSegments to UserDefaults: \(error)")
75	            }
76	        }
77	    }
78	
79	    public var menuBarSegmentsInitialized: Bool {
80	        get { defaults.bool(forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
81	        set { defaults.set(newValue, forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
82	    }
83	}
84	
85	// MARK: - In-memory test double
86	
87	/// Shared between production defaults-absent paths and test code.
88	@Observable
89	@MainActor
90	public final class InMemoryAppPreferences: AppPreferences {
91	    public var refreshInterval: RefreshInterval
92	    public var launchAtLogin: Bool
93	    public var logLevel: LogLevel
94	    public var menuBarSegments: [MenuBarSegmentConfig]
95	    public var menuBarSegmentsInitialized: Bool
96	
97	    public init(
98	        refreshInterval: RefreshInterval = .default,
99	        launchAtLogin: Bool = false,
100	        logLevel: LogLevel = .info,
101	        menuBarSegments: [MenuBarSegmentConfig] = [],
102	        menuBarSegmentsInitialized: Bool = false
